code.styles.css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  html, body {
    font-family: "Neue Montreal";
  }

  nav {
    position: fixed;
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 2em;
  }

  nav a, button {
    font-family: "PP Editorial Old";
  }

  nav a {
    color: #fff;
    text-decoration: none;
  }

  button {
    padding: 1em 2em;
    border: none;
    background: rgba(255, 255, 255, 0.15);
    border: 1px solid #fff;
    border-radius: 50px;
    color: #fff;
    z-index: 10000;
  }

  .container {
    padding: 10em 2em 5em 2em;
    width: 100%;
    height: 100%;
    background: #0f0f0f;
  }

  h1 {
    color: #fff;
    font-family: "PP Editorial Old";
    font-size: 60px;
    font-weight: lighter;
  }

  .gallery {
    position: relative;
    width: 100%;
    display: flex;
    background: #0f0f0f;
    color: #fff;
    padding: 5em 2em;
    z-index: -1;
  }

  .minimap {
    position: sticky;
    top: 0;
    width: 20%;
    height: 100vh;
    padding: 2em 0;
    display: flex;
    justify-content: center;
    align-items: center;
  }

  .images {
    position: relative;
    top: 0;
    width: 80%;
  }

  .img {
    position: relative;
    width: 800px;
    height: 1000px;
    border-radius: 40px;
    overflow: hidden;
    margin: 50px auto;
  }

  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .img-thumbnail {
    position: relative;
    width: 50px;
    height: 70px;
    border-radius: 10px;
    overflow: hidden;
    opacity: 0.5;
  }

  @media(max-width: 900px) {
    .img {
      width: 400px;
      height: 500px;
    }
  }
